arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    //---------- Movement ----------
    moveTime+=1
    if moveTime>=45
    {
      xVel*=-1
      moveTime=irandom(5)
    }
    
    if throwTime<throwDelay
    {
      if x>oPlayer1.x
        image_xscale=-1
      else
        image_xscale=1
    }
    
    //---------- Throw fire ----------
    throwTime+=1
    if throwTime>=throwDelay
    {
      if throwTime=throwDelay //change anim
        sprite_index=sFirebirdThrow
      else if throwTime=throwDelay+6 //Throw fire
      {
        var tNewAttack;
        tNewAttack=instance_create(x-(4*image_xscale),y-24,oFirebirdFire)
        if image_xscale=-1
          tNewAttack.image_xscale=-1
        tNewAttack.atkPower=atkPower
        tNewAttack.xVel=random_range(2.5,4)*image_xscale
        tNewAttack.yVel=-random_range(4,5)
        throwCycle+=1
        if throwCycle=5
        {
          throwDelay=26
          throwCycle=0
        }
        else
          throwDelay=13
        sprite_index=sFirebirdWalk
        throwTime=0
      }
    }
    
    yVel+=0.35
    if isCollisionBottom(1)
    {
      y-=2
      extraHeight+=1
      if extraHeight mod 4=0
        yVel=-4
      else
        yVel=-2
    }
    if isCollisionLeft(1)
      xVel=runAcc
    if isCollisionRight(1)
      xVel=-runAcc
    if isCollisionSolid()
      y-=2
    
    moveTo(xVel,yVel)
    if y>room_height+24
      instance_destroy()
  }
  enemyStepEvent()
}

if bSpotted=0
{
  if checkScreenArea(x,y,2)=1
  {
    global.recBirdsSeen+=1
    bSpotted=1
  }
}
